from collections import deque

def shortest_path(kg, start: str, end: str) -> list:
    if start == end:
        return [start]
    visited = {start: None}  # entity -> previous entity
    queue = deque([start])
    while queue:
        entity = queue.popleft()
        for _, neighbor in kg.neighbors(entity):
            if neighbor not in visited:
                visited[neighbor] = entity
                if neighbor == end:
                    # Reconstruct path
                    path = []
                    cur = end
                    while cur is not None:
                        path.append(cur)
                        cur = visited[cur]
                    return path[::-1]
                queue.append(neighbor)
    return []

def shortest_path_with_relations(kg, start: str, end: str) -> list:
    if start == end:
        return [(start, None)]
    # BFS storing (entity, relation_used)
    visited = {start: (None, None)}  # entity -> (prev_entity, relation)
    queue = deque([start])
    while queue:
        entity = queue.popleft()
        for rel, neighbor in kg.neighbors(entity):
            if neighbor not in visited:
                visited[neighbor] = (entity, rel)
                if neighbor == end:
                    path = []
                    cur = end
                    while cur is not None:
                        prev, rel_in = visited[cur]
                        if prev is None:
                            path.append((cur, None))
                        else:
                            path.append((cur, rel_in))
                        cur = prev
                    path.reverse()
                    # Fix: last entity should have None relation
                    path[-1] = (path[-1][0], None)
                    return path
                queue.append(neighbor)
    return []

